const SECRET = 'GDA-CTRL-2026-xK9mPqR7vNwL3hBdY8tZcFjUeA4s';
const ALLOWED = ['edit-file','run-tests','deploy','read-file','status'];
const ROOTS = ['/opt/gda-command/','/root/gda-frontend/','/root/n8n-envision/'];

const req = $input.first().json;
const headers = req.headers || {};
const incoming = (headers['x-gda-auth'] || '').trim();
const body = req.body || {};
const ts = new Date().toISOString();

// AUTH
if (incoming !== SECRET) {
  return [{ json: {
    __skipSSH: true, __ts: ts, __action: 'auth-fail',
    __status: 401,
    __prebuilt: { success:false, error:'UNAUTHORIZED', message:'Missing or invalid X-GDA-Auth header' },
    __cmd: 'echo noop'
  }}];
}

const action = body.action || '';
const rawPath = body.path || null;
const content = body.content || null;
const meta = body.meta || {};

// ACTION ALLOWLIST
if (!ALLOWED.includes(action)) {
  return [{ json: {
    __skipSSH: true, __ts: ts, __action: action,
    __status: 400,
    __prebuilt: { success:false, error:'INVALID_ACTION', allowed: ALLOWED },
    __cmd: 'echo noop'
  }}];
}

console.log('GDA_AUDIT:', JSON.stringify({ ts, action, path: rawPath, contentLength: content ? content.length : 0, meta }));

// DRY-RUN
if (['status','run-tests','deploy'].includes(action)) {
  return [{ json: {
    __skipSSH: true, __ts: ts, __action: action,
    __status: 200,
    __prebuilt: { success:true, action, dryRun:true, logged:true, timestamp:ts, note:'deploy and run-tests are log-only. No execution performed.' },
    __cmd: 'echo noop'
  }}];
}

// PATH VALIDATION
function vPath(p) {
  if (!p) return { ok:false, reason:'PATH_REQUIRED' };
  if (p.includes('..')) return { ok:false, reason:'PATH_TRAVERSAL_REJECTED' };
  if (p.includes('\0')) return { ok:false, reason:'NULL_BYTE_REJECTED' };
  const r = p.startsWith('/') ? p : '/opt/gda-command/' + p;
  if (!ROOTS.some(root => r.startsWith(root))) return { ok:false, reason:'PATH_NOT_ALLOWLISTED' };
  return { ok:true, resolved:r };
}

const pv = vPath(rawPath);
if (!pv.ok) {
  return [{ json: {
    __skipSSH: true, __ts: ts, __action: action,
    __status: 400,
    __prebuilt: { success:false, error:pv.reason, action, path:rawPath, timestamp:ts },
    __cmd: 'echo noop'
  }}];
}

// FILE OPS — build SSH command, let SSH node execute
let cmd;
if (action === 'read-file') {
  cmd = 'cat ' + pv.resolved;
} else {
  // edit-file: base64-encode content so it survives shell quoting completely
  const b64 = Buffer.from(content || '').toString('base64');
  const tmp = '/tmp/gda_' + Date.now();
  cmd = 'bash -c "echo ' + b64 + ' | base64 -d > ' + tmp + ' && mv ' + tmp + ' ' + pv.resolved + ' && echo WRITE_OK"';
}

return [{ json: {
  __skipSSH: false, __ts: ts, __action: action,
  __resolvedPath: pv.resolved,
  __content: content,
  __cmd: cmd
}}];

const gate = $('Gate').first().json;
const ssh = $input.first().json;

// If gate short-circuited (auth fail, dry-run, path error), return prebuilt
if (gate.__skipSSH) {
  return [{ json: { __status: gate.__status, __body: gate.__prebuilt } }];
}

// SSH ran — build response from SSH output
const stdout = ssh.stdout || '';
const stderr = ssh.stderr || '';
const ts = gate.__ts;
const action = gate.__action;
const path = gate.__resolvedPath;

if (action === 'read-file') {
  return [{ json: { __status: 200, __body: { success:true, action:'read-file', path, content:stdout, stderr, timestamp:ts } } }];
}

// edit-file
const ok = stdout.trim() === 'WRITE_OK' && stderr === '';
return [{ json: { __status: 200, __body: { success:ok, action:'edit-file', path, bytesWritten:(gate.__content||'').length, stderr, timestamp:ts } } }];
